// AWS_SECRET_KEY=your_secret_here
// AWS_BUCKET=your_bucket_name
// AWS_REGION=us-east-1
// GOOGLE_VISION_API_KEY=your_key_here

// STEP 2: Add .env to your .gitignore BEFORE your first commit:
// echo ".env" >> .gitignore

