class PhotoAnalyzerScreen extends StatefulWidget {
  const PhotoAnalyzerScreen({super.key});

  @override
  State<PhotoAnalyzerScreen> createState() => _PhotoAnalyzerScreenState();
}

class _PhotoAnalyzerScreenState extends State<PhotoAnalyzerScreen> {
  final ImagePicker _picker = ImagePicker();
  File? _selectedImage;
  String? _uploadedUrl;
  List<VisionResult> _analysisResults = [];
  bool _isUploading = false;
  bool _isAnalyzing = false;
  String? _errorMessage;

  String get _awsAccessKey => dotenv.env['AWS_ACCESS_KEY'] ?? '';
  String get _awsSecretKey => dotenv.env['AWS_SECRET_KEY'] ?? '';
  String get _awsBucket => dotenv.env['AWS_BUCKET'] ?? '';
  String get _awsRegion => dotenv.env['AWS_REGION'] ?? 'us-east-1';
  String get _googleApiKey => dotenv.env['GOOGLE_VISION_API_KEY'] ?? '';

  @override
  void initState() {
    super.initState();
    _validateConfig();
  }

  void _validateConfig() {
    if (_awsAccessKey.isEmpty ||
        _awsSecretKey.isEmpty ||
        _googleApiKey.isEmpty) {
      setState(() {
        _errorMessage =
            'Missing credentials in .env file. See README for setup.';
      });
    }
  }

  Future<void> _pickImage(ImageSource source) async {
    try {
      final XFile? pickedFile = await _picker.pickImage(
        source: source,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );

      if (pickedFile != null) {
        setState(() {
          _selectedImage = File(pickedFile.path);
          _uploadedUrl = null;
          _analysisResults = [];
          _errorMessage = null;
        });
      }
    } catch (e) {
      setState(() {
        _errorMessage = 'Failed to pick image: $e';
      });
    }
  }

  Future<void> _uploadToS3() async {
    if (_selectedImage == null) return;

    setState(() {
      _isUploading = true;
      _errorMessage = null;
    });

    try {
      final String fileName =
          'hackathon/${DateTime.now().millisecondsSinceEpoch}_${_selectedImage!.path.split('/').last}';

      final String? uploadedUrl = await AwsS3.uploadFile(
        accessKey: _awsAccessKey,
        secretKey: _awsSecretKey,
        file: _selectedImage!,
        bucket: _awsBucket,
        region: _awsRegion,
        destDir: 'hackathon-uploads',
        filename: fileName,
      );

      setState(() {
        _uploadedUrl = uploadedUrl;
        _isUploading = false;
      });

      if (_uploadedUrl != null) {
        await _analyzeWithVision();
      }
    } catch (e) {
      setState(() {
        _isUploading = false;
        _errorMessage = 'Upload failed: $e';
      });
    }
  }

  Future<void> _analyzeWithVision() async {
    if (_selectedImage == null) return;

    setState(() {
      _isAnalyzing = true;
      _errorMessage = null;
    });

    try {
      final bytes = await _selectedImage!.readAsBytes();
      final base64Image = base64Encode(bytes);

      final url = Uri.parse(
        'https://vision.googleapis.com/v1/images:annotate?key=$_googleApiKey',
      );

      final requestBody = jsonEncode({
        'requests': [
          {
            'image': {'content': base64Image},
            'features': [
              {'type': 'LABEL_DETECTION', 'maxResults': 10},
              {'type': 'FACE_DETECTION', 'maxResults': 5},
              {'type': 'TEXT_DETECTION', 'maxResults': 5},
              {'type': 'SAFE_SEARCH_DETECTION'},
              {'type': 'IMAGE_PROPERTIES', 'maxResults': 5},
              {'type': 'OBJECT_LOCALIZATION', 'maxResults': 10},
            ],
          }
        ],
      });

      final response = await http.post(
        url,
        headers: {'Content-Type': 'application/json'},
        body: requestBody,
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        final annotations = data['responses'][0];
        _parseVisionResults(annotations);
      } else {
        final errorData = jsonDecode(response.body);
        setState(() {
          _errorMessage =
              'Vision API error: ${errorData['error']?['message'] ?? response.statusCode}';
        });
      }
    } catch (e) {
      setState(() {
        _errorMessage = 'Analysis failed: $e';
      });
    } finally {
      setState(() {
        _isAnalyzing = false;
      });
    }
  }

  void _parseVisionResults(Map<String, dynamic> annotations) {
    final List<VisionResult> results = [];

    // Labels
    if (annotations['labelAnnotations'] != null) {
      for (var label in annotations['labelAnnotations']) {
        results.add(VisionResult(
          category: 'Label',
          description: label['description'],
          confidence: (label['score'] * 100).toStringAsFixed(1),
          icon: Icons.label,
        ));
      }
    }

    // Faces
    if (annotations['faceAnnotations'] != null) {
      final faceCount = annotations['faceAnnotations'].length;
      for (var face in annotations['faceAnnotations']) {
        results.add(VisionResult(
          category: 'Face',
          description:
              'Face detected - Joy: ${face['joyLikelihood']}, Sorrow: ${face['sorrowLikelihood']}',
          confidence: face['detectionConfidence'] != null
              ? (face['detectionConfidence'] * 100).toStringAsFixed(1)
              : 'N/A',
          icon: Icons.face,
        ));
      }
      if (faceCount == 0) {
        results.add(VisionResult(
          category: 'Face',
          description: 'No faces detected',
          confidence: '-',
          icon: Icons.face,
        ));
      }
    }

    // Text
    if (annotations['textAnnotations'] != null &&
        annotations['textAnnotations'].isNotEmpty) {
      final fullText = annotations['textAnnotations'][0]['description'];
      results.add(VisionResult(
        category: 'Text (OCR)',
        description: fullText.toString().length > 200
            ? '${fullText.toString().substring(0, 200)}...'
            : fullText.toString(),
        confidence: '-',
        icon: Icons.text_fields,
      ));
    }

    // Objects
    if (annotations['localizedObjectAnnotations'] != null) {
      for (var obj in annotations['localizedObjectAnnotations']) {
        results.add(VisionResult(
          category: 'Object',
          description: obj['name'],
          confidence: (obj['score'] * 100).toStringAsFixed(1),
          icon: Icons.category,
        ));
      }
    }

    // Safe Search
    if (annotations['safeSearchAnnotation'] != null) {
      final ss = annotations['safeSearchAnnotation'];
      results.add(VisionResult(
        category: 'Safe Search',
        description:
            'Adult: ${ss['adult']}, Violence: ${ss['violence']}, Racy: ${ss['racy']}',
        confidence: '-',
        icon: Icons.shield,
      ));
    }

    // Dominant Colors
    if (annotations['imagePropertiesAnnotation'] != null) {
      final colors = annotations['imagePropertiesAnnotation']
          ?['dominantColors']?['colors'];
      if (colors != null && colors.isNotEmpty) {
        final topColors = colors.take(3).map((c) {
          final color = c['color'];
          return 'RGB(${color['red']?.toInt() ?? 0}, ${color['green']?.toInt() ?? 0}, ${color['blue']?.toInt() ?? 0})';
        }).join(', ');
        results.add(VisionResult(
          category: 'Colors',
          description: 'Dominant: $topColors',
          confidence: '-',
          icon: Icons.palette,
        ));
      }
    }

    setState(() {
      _analysisResults = results;
    });
  }

  Future<void> _processImage() async {
    await _uploadToS3();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('🏆 Photo Analyzer'),
        centerTitle: true,
        actions: [
          if (_selectedImage != null)
            IconButton(
              icon: const Icon(Icons.refresh),
              onPressed: () {
                setState(() {
                  _selectedImage = null;
                  _uploadedUrl = null;
                  _analysisResults = [];
                  _errorMessage = null;
                });
              },
            ),
        ],
      ),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // Error Banner
            if (_errorMessage != null)
              Container(
                margin: const EdgeInsets.only(bottom: 16),
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: Colors.red.shade900.withOpacity(0.3),
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(color: Colors.red.shade700),
                ),
                child: Row(
                  children: [
                    const Icon(Icons.error_outline, color: Colors.redAccent),
                    const SizedBox(width: 8),
                    Expanded(
                      child: Text(
                        _errorMessage!,
                        style: const TextStyle(color: Colors.redAccent),
                      ),
                    ),
                    IconButton(
                      icon: const Icon(Icons.close, size: 18),
                      onPressed: () =>
                          setState(() => _errorMessage = null),
                    ),
                  ],
                ),
              ),

            // Image Preview
            Container(
              height: 300,
              decoration: BoxDecoration(
                color: Colors.grey.shade900,
                borderRadius: BorderRadius.circular(16),
                border: Border.all(color: Colors.grey.shade700),
              ),
              child: _selectedImage != null
                  ? ClipRRect(
                      borderRadius: BorderRadius.circular(16),
                      child: Image.file(
                        _selectedImage!,
                        fit: BoxFit.cover,
                        width: double.infinity,
                      ),
                    )
                  : Column(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: [
                        Icon(Icons.add_photo_alternate_outlined,
                            size: 64, color: Colors.grey.shade600),
                        const SizedBox(height: 8),
                        Text(
                          'Select a photo to analyze',
                          style: TextStyle(color: Colors.grey.shade500),
                        ),
                      ],
                    ),
            ),

            const SizedBox(height: 16),

            // Source Buttons
            Row(
              children: [
                Expanded(
                  child: ElevatedButton.icon(
                    onPressed: (_isUploading || _isAnalyzing)
                        ? null
                        : () => _pickImage(ImageSource.camera),
                    icon: const Icon(Icons.camera_alt),
                    label: const Text('Camera'),
                    style: ElevatedButton.styleFrom(
                      padding: const EdgeInsets.symmetric(vertical: 14),
                    ),
                  ),
                ),
                const SizedBox(width: 12),
                Expanded(
                  child: ElevatedButton.icon(
                    onPressed: (_isUploading || _isAnalyzing)
                        ? null
                        : () => _pickImage(ImageSource.gallery),
                    icon: const Icon(Icons.photo_library),
                    label: const Text('Gallery'),
                    style: ElevatedButton.styleFrom(
                      padding: const EdgeInsets.symmetric(vertical: 14),
                    ),
                  ),
                ),
              ],
            ),

            const SizedBox(height: 12),

            // Analyze Button
            FilledButton.icon(
              onPressed:
                  (_selectedImage != null && !_isUploading && !_isAnalyzing)
                      ? _processImage
                      : null,
              icon: (_isUploading || _isAnalyzing)
                  ? const SizedBox(
                      width: 18,
                      height: 18,
                      child: CircularProgressIndicator(
                          strokeWidth: 2, color: Colors.white),
                    )
                  : const Icon(Icons.auto_awesome),
              label: Text(
                _isUploading
                    ? 'Uploading to S3...'
                    : _isAnalyzing
                        ? 'Analyzing with Vision AI...'
                        : 'Upload & Analyze',
              ),
              style: FilledButton.styleFrom(
                padding: const EdgeInsets.symmetric(vertical: 16),
                textStyle: const TextStyle(fontSize: 16),
              ),
            ),

            // Upload URL
            if (_uploadedUrl != null) ...[
              const SizedBox(height: 16),
              Container(
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: Colors.green.shade900.withOpacity(0.3),
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(color: Colors.green.shade700),
                ),
                child: Row(
                  children: [
                    const Icon(Icons.cloud_done, color: Colors.greenAccent),
                    const SizedBox(width: 8),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          const Text('Uploaded to S3',
                              style: TextStyle(
                                  color: Colors.greenAccent,
                                  fontWeight: FontWeight.bold)),
                          Text(
                            _uploadedUrl!,
                            style: TextStyle(
                                color: Colors.grey.shade400, fontSize: 11),
                            maxLines: 2,
                            overflow: TextOverflow.ellipsis,
                          ),
                        ],
                      ),
                    ),
                  ],
                ),
              ),
            ],

            // Analysis Results
            if (_analysisResults.isNotEmpty) ...[
              const SizedBox(height: 24),
              Row(
                children: [
                  const Icon(Icons.analytics, color: Colors.deepPurpleAccent),
                  const SizedBox(width: 8),
                  Text(
                    'Analysis Results (${_analysisResults.length})',
                    style: Theme.of(context).textTheme.titleLarge?.copyWith(
                          fontWeight: FontWeight.bold,
                        ),
                  ),
                ],
              ),
              const SizedBox(height: 12),
              ..._analysisResults.map((result) => _buildResultCard(result)),
            ],
          ],
        ),
      ),
    );
  }

  Widget _buildResultCard(VisionResult result) {
    return Card(
      margin: const EdgeInsets.only(bottom: 8),
      child: ListTile(
        leading: CircleAvatar(
          backgroundColor: Colors.deepPurple.shade800,
          child: Icon(result.icon, size: 20, color: Colors.deepPurpleAccent),
        ),
        title: Text(
          result.category,
          style: const TextStyle(
              fontWeight: FontWeight.bold, fontSize: 13, color: Colors.grey),
        ),
        subtitle: Text(result.description),
        trailing: result.confidence != '-' && result.confidence != 'N/A'
            ? Container(
                padding:
                    const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                decoration: BoxDecoration(
                  color: _getConfidenceColor(
                          double.tryParse(result.confidence) ?? 0)
                      .withOpacity(0.2),
                  borderRadius: BorderRadius.circular(20),
                ),
                child: Text(
                  '${result.confidence}%',
                  style: TextStyle(
                    color: _getConfidenceColor(
                        double.tryParse(result.confidence) ?? 0),
                    fontWeight: FontWeight.bold,
                    fontSize: 12,
                  ),
                ),
              )
            : null,
      ),
    );
  }

  Color _getConfidenceColor(double confidence) {
    if (confidence >= 80) return Colors.greenAccent;
    if (confidence >= 50) return Colors.orangeAccent;
    return Colors.redAccent;
  }
}

class VisionResult {
  final String category;
  final String description;
  final String confidence;
  final IconData icon;

  VisionResult({
    required this.category,
    required this.description,
    required this.confidence,
    required this.icon,
  });
}

